1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import {
5	  Dialog,
6	  DialogContent,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Textarea } from "@/components/ui/textarea";
10	import {
11	  Printer, CheckCircle2, FileSignature, PenTool,
12	  Edit3, Save, X, Maximize2, Minimize2, Download
13	} from "lucide-react";
14	import { format } from "date-fns";
15	import { toast } from "sonner";
16	import { cn } from "@/lib/utils";
17	import ESignatureDialog from "./ESignatureDialog";
18	import { useDownloadPDF } from "@/hooks/use-download-pdf";
19	
20	interface ContractPreviewDialogProps {
21	  open: boolean;
22	  onOpenChange: (open: boolean) => void;
23	  contract: any;
24	  onContractUpdate?: () => void;
25	}
26	
27	const ContractPreviewDialog = ({
28	  open,
29	  onOpenChange,
30	  contract,
31	  onContractUpdate,
32	}: ContractPreviewDialogProps) => {
33	  const [profile, setProfile] = useState<any>(null);
34	  const [showSignatureDialog, setShowSignatureDialog] = useState(false);
35	  const [placementMode, setPlacementMode] = useState<{ signature: string; signedAt: string } | null>(null);
36	  const [localContract, setLocalContract] = useState(contract);
37	  const [isEditingDetails, setIsEditingDetails] = useState(false);
38	  const [editableContent, setEditableContent] = useState("");
39	  const [savingDetails, setSavingDetails] = useState(false);
40	  const [isFullscreen, setIsFullscreen] = useState(false);
41	  const { ref: docRef, download, downloading } = useDownloadPDF(
42	    contract ? `Contract-${contract.title?.replace(/\s+/g, "-")}` : "Contract"
43	  );
44	
45	  useEffect(() => {
46	    if (contract) {
47	      fetchProfile();
48	      setLocalContract(contract);
49	      setEditableContent(contract.content || "");
50	      setIsEditingDetails(false);
51	      setPlacementMode(null);
52	    }
53	  }, [contract]);
54	
55	  const fetchProfile = async () => {
56	    const { data: { session } } = await supabase.auth.getSession();
57	    if (session) {
58	      const { data } = await supabase
59	        .from("profiles")
60	        .select("*")
61	        .eq("id", session.user.id)
62	        .single();
63	      setProfile(data);
64	    }
65	  };
66	
67	  const handlePrint = () => window.print();
68	
69	  // After drawing/typing in the signature pad, enter placement mode
70	  const handleSignReady = (signature: string, signedAt: string) => {
71	    setShowSignatureDialog(false);
72	    setPlacementMode({ signature, signedAt });
73	  };
74	
75	  // User taps anywhere on the placement overlay → save signature
76	  const handlePlacementTap = async () => {
77	    if (!placementMode || !localContract) return;
78	    const { signature, signedAt } = placementMode;
79	    const { error } = await supabase
80	      .from("contracts")
81	      .update({ creator_signature: signature, creator_signed_at: signedAt, status: "signed" })
82	      .eq("id", localContract.id);
83	    if (error) { toast.error("Failed to save signature"); return; }
84	    setLocalContract({ ...localContract, creator_signature: signature, creator_signed_at: signedAt, status: "signed" });
85	    setPlacementMode(null);
86	    toast.success("Your signature has been placed!");
87	    onContractUpdate?.();
88	  };
89	
90	  const handleSaveDetails = async () => {
91	    if (!localContract) return;
92	    setSavingDetails(true);
93	    const { error } = await supabase
94	      .from("contracts")
95	      .update({ content: editableContent || null })
96	      .eq("id", localContract.id);
97	    setSavingDetails(false);
98	    if (error) { toast.error("Failed to save changes"); return; }
99	    setLocalContract({ ...localContract, content: editableContent || null });
100	    setIsEditingDetails(false);
101	    toast.success("Contract updated");
102	    onContractUpdate?.();
103	  };
104	
105	  if (!contract || !localContract) return null;
106	
107	  const statusConfig: Record<string, { label: string; color: string; bg: string }> = {
108	    draft:     { label: "Draft",     color: "text-muted-foreground", bg: "bg-muted" },
109	    sent:      { label: "Sent",      color: "text-blue-600",         bg: "bg-blue-500/10" },
110	    signed:    { label: "Signed",    color: "text-emerald-600",      bg: "bg-emerald-500/10" },
111	    active:    { label: "Active",    color: "text-green-600",        bg: "bg-green-500/10" },
112	    completed: { label: "Completed", color: "text-purple-600",       bg: "bg-purple-500/10" },
113	    cancelled: { label: "Cancelled", color: "text-destructive",      bg: "bg-destructive/10" },
114	  };
115	
116	  const status = statusConfig[localContract.status] || statusConfig.draft;
117	
118	  // Signature card — shows pending preview during placement mode, or the sign/signed state otherwise
119	  const SignatureSection = () => (
120	    <div className="pt-6 border-t border-border/30 space-y-4">
121	      <div className="flex items-center gap-2">
122	        <FileSignature className="h-4 w-4 text-primary" />
123	        <p className="text-[10px] uppercase tracking-[0.15em] text-muted-foreground font-semibold">
124	          {placementMode ? "Signature Ready — tap document to place" : "Your Signature"}
125	        </p>
126	      </div>
127	
128	      {placementMode ? (
129	        // Pending signature preview while placement mode is active
130	        <div className="h-24 rounded-2xl border-2 border-dashed border-primary/30 bg-primary/5 flex items-center justify-center overflow-hidden">
131	          {placementMode.signature.startsWith("data:image") ? (
132	            <img src={placementMode.signature} alt="Your signature" className="max-h-20 object-contain" />
133	          ) : (
134	            <span className="text-3xl font-vollkorn italic text-foreground/60">{placementMode.signature}</span>
135	          )}
136	        </div>
137	      ) : (
138	        <div
139	          className={cn(
140	            "h-36 rounded-2xl border-2 border-dashed flex items-center justify-center relative overflow-hidden transition-all",
141	            localContract.creator_signature
142	              ? "border-emerald-500/30 bg-emerald-500/5"
143	              : "border-border hover:border-primary/30 hover:bg-primary/5 cursor-pointer"
144	          )}
145	          onClick={(e) => { e.stopPropagation(); if (!localContract.creator_signature) setShowSignatureDialog(true); }}
146	        >
147	          {localContract.creator_signature ? (
148	            <>
