1	import { useState, useEffect, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import {
5	  Dialog,
6	  DialogContent,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Textarea } from "@/components/ui/textarea";
10	import {
11	  Printer, CheckCircle2, FileSignature, PenTool,
12	  Edit3, Save, X, Maximize2, Minimize2, Download,
13	} from "lucide-react";
14	import { format } from "date-fns";
15	import { toast } from "sonner";
16	import { cn } from "@/lib/utils";
17	import ESignatureDialog from "./ESignatureDialog";
18	import { useDownloadPDF } from "@/hooks/use-download-pdf";
19	
20	// ─── Signature position on the document canvas ───────────────────────────────
21	
22	interface SigPos { x: number; y: number; w: number; h: number }
23	
24	const MIN_W = 80;
25	const MIN_H = 40;
26	const DEFAULT_W = 220;
27	const DEFAULT_H = 88;
28	
29	// ─── Draggable + resizable signature widget ───────────────────────────────────
30	// Defined outside the main component so React doesn't unmount it on re-renders.
31	
32	interface DraggableSigProps {
33	  pos: SigPos;
34	  signature: string;
35	  onChange: (pos: SigPos) => void;
36	}
37	
38	const DraggableSig = ({ pos, signature, onChange }: DraggableSigProps) => {
39	  const dragRef = useRef<{ sx: number; sy: number; ox: number; oy: number } | null>(null);
40	  const resizeRef = useRef<{ corner: string; sx: number; sy: number; orig: SigPos } | null>(null);
41	
42	  // ── Drag body ──────────────────────────────────────────────────────────────
43	  const onBodyDown = (e: React.PointerEvent<HTMLDivElement>) => {
44	    e.preventDefault();
45	    e.currentTarget.setPointerCapture(e.pointerId);
46	    dragRef.current = { sx: e.clientX, sy: e.clientY, ox: pos.x, oy: pos.y };
47	  };
48	  const onBodyMove = (e: React.PointerEvent<HTMLDivElement>) => {
49	    if (!dragRef.current) return;
50	    onChange({
51	      ...pos,
52	      x: dragRef.current.ox + (e.clientX - dragRef.current.sx),
53	      y: dragRef.current.oy + (e.clientY - dragRef.current.sy),
54	    });
55	  };
56	  const onBodyUp = () => { dragRef.current = null; };
57	
58	  // ── Resize corners ──────────────────────────────────────────────────────────
59	  const cornerHandlers = (corner: string) => ({
60	    onPointerDown: (e: React.PointerEvent<HTMLDivElement>) => {
61	      e.preventDefault();
62	      e.stopPropagation();
63	      e.currentTarget.setPointerCapture(e.pointerId);
64	      resizeRef.current = { corner, sx: e.clientX, sy: e.clientY, orig: { ...pos } };
65	    },
66	    onPointerMove: (e: React.PointerEvent<HTMLDivElement>) => {
67	      if (!resizeRef.current || resizeRef.current.corner !== corner) return;
68	      const dx = e.clientX - resizeRef.current.sx;
69	      const dy = e.clientY - resizeRef.current.sy;
70	      const o = resizeRef.current.orig;
71	      let { x, y, w, h } = o;
72	      if (corner === "se") { w = Math.max(MIN_W, o.w + dx);                          h = Math.max(MIN_H, o.h + dy); }
73	      if (corner === "sw") { x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx); h = Math.max(MIN_H, o.h + dy); }
74	      if (corner === "ne") { w = Math.max(MIN_W, o.w + dx); y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy); }
75	      if (corner === "nw") {
76	        x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx);
77	        y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy);
78	      }
79	      onChange({ x, y, w, h });
80	    },
81	    onPointerUp: () => { resizeRef.current = null; },
82	  });
83	
84	  const CORNERS = [
85	    { id: "nw", cls: "-top-2 -left-2 cursor-nw-resize" },
86	    { id: "ne", cls: "-top-2 -right-2 cursor-ne-resize" },
87	    { id: "sw", cls: "-bottom-2 -left-2 cursor-sw-resize" },
88	    { id: "se", cls: "-bottom-2 -right-2 cursor-se-resize" },
89	  ];
90	
91	  const fontSize = Math.max(14, Math.min(pos.h * 0.38, 48));
92	
93	  return (
94	    <div
95	      className="absolute touch-none"
96	      style={{ left: pos.x, top: pos.y, width: pos.w, height: pos.h, zIndex: 50 }}
97	      onClick={(e) => e.stopPropagation()}
98	    >
99	      {/* Body — drag to move */}
100	      <div
101	        className="w-full h-full rounded-lg border-2 border-primary bg-white/95 dark:bg-zinc-900/95 shadow-[0_4px_24px_rgba(0,0,0,0.18)] flex items-center justify-center overflow-hidden cursor-move select-none"
102	        onPointerDown={onBodyDown}
103	        onPointerMove={onBodyMove}
104	        onPointerUp={onBodyUp}
105	      >
106	        {signature.startsWith("data:image") ? (
107	          <img
108	            src={signature}
109	            alt="Signature"
110	            className="max-w-full max-h-full object-contain p-1"
111	            draggable={false}
112	          />
113	        ) : (
114	          <span
115	            className="font-vollkorn italic text-foreground/85 truncate px-2 pointer-events-none select-none"
116	            style={{ fontSize }}
117	          >
118	            {signature}
119	          </span>
120	        )}
121	      </div>
122	
123	      {/* Resize handles */}
124	      {CORNERS.map(({ id, cls }) => (
125	        <div
126	          key={id}
127	          className={cn(
128	            "absolute w-4 h-4 bg-white border-2 border-primary rounded-sm shadow-md touch-none z-10",
129	            cls
130	          )}
131	          {...cornerHandlers(id)}
132	        />
133	      ))}
134	    </div>
135	  );
136	};
137	
138	// ─── Main Dialog ──────────────────────────────────────────────────────────────
139	
140	interface ContractPreviewDialogProps {
141	  open: boolean;
142	  onOpenChange: (open: boolean) => void;
143	  contract: any;
144	  onContractUpdate?: () => void;
145	}
146	
147	const ContractPreviewDialog = ({
148	  open,
149	  onOpenChange,
150	  contract,
151	  onContractUpdate,
152	}: ContractPreviewDialogProps) => {
153	  const [profile, setProfile]                 = useState<any>(null);
154	  const [showSignatureDialog, setShowSignatureDialog] = useState(false);
155	  const [placementMode, setPlacementMode]     = useState<{
156	    signature: string;
157	    signedAt: string;
158	    pos: SigPos | null;
159	  } | null>(null);
160	  const [savingSignature, setSavingSignature] = useState(false);
161	  const [localContract, setLocalContract]     = useState(contract);
162	  const [isEditingDetails, setIsEditingDetails] = useState(false);
163	  const [editableContent, setEditableContent] = useState("");
164	  const [savingDetails, setSavingDetails]     = useState(false);
165	  const [isFullscreen, setIsFullscreen]       = useState(false);
166	
167	  // ref for the position:relative wrapper that contains the document card
168	  const docWrapperRef = useRef<HTMLDivElement>(null);
169	
170	  const { ref: docRef, download, downloading } = useDownloadPDF(
171	    contract ? `Contract-${contract.title?.replace(/\s+/g, "-")}` : "Contract"
172	  );
173	
174	  useEffect(() => {
175	    if (contract) {
176	      fetchProfile();
177	      setLocalContract(contract);
178	      setEditableContent(contract.content || "");
179	      setIsEditingDetails(false);
180	      setPlacementMode(null);
181	    }
182	  }, [contract]);
