364	              stat.accent === "amber" ? "from-amber-500/5 to-transparent" :
365	              "from-blue-500/5 to-transparent"
366	            }`} />
367	            <div className="relative">
368	              <div className={`w-8 h-8 rounded-xl flex items-center justify-center mb-2 ${
369	                stat.accent === "primary" ? "bg-primary/10 text-primary" :
370	                stat.accent === "emerald" ? "bg-emerald-500/10 text-emerald-500" :
371	                stat.accent === "amber" ? "bg-amber-500/10 text-amber-500" :
372	                "bg-blue-500/10 text-blue-500"
373	              }`}>
374	                {stat.icon}
375	              </div>
376	              <p className={`font-bold text-foreground ${stat.label === "Value" ? "text-base md:text-lg" : "text-2xl md:text-3xl"}`}>
377	                {stat.value}
378	              </p>
379	              <p className="text-xs text-muted-foreground mt-0.5">{stat.label}</p>
380	            </div>
381	          </div>
382	        ))}
383	      </motion.div>
384	
385	      {/* Search & Filters — Unified Bar */}
386	      <motion.div 
387	        initial={{ opacity: 0, y: 12 }}
388	        animate={{ opacity: 1, y: 0 }}
389	        transition={{ delay: 0.1 }}
390	        className="flex flex-col gap-2 lg:flex-row"
391	      >
392	        <div className="relative flex-1">
393	          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
394	          <Input
395	            placeholder="Search contracts, clients..."
396	            value={searchQuery}
397	            onChange={(e) => setSearchQuery(e.target.value)}
398	            className="pl-10 h-10 rounded-xl bg-muted/50 border-0 focus:bg-background focus:ring-1 focus:ring-primary/20 transition-all"
399	          />
400	        </div>
401	        <Select value={statusFilter} onValueChange={setStatusFilter}>
402	          <SelectTrigger className="w-full sm:w-[130px] h-10 rounded-xl bg-muted/50 border-0">
403	            <Filter className="h-3.5 w-3.5 mr-1.5 text-muted-foreground" />
404	            <SelectValue placeholder="Status" />
405	          </SelectTrigger>
406	          <SelectContent>
407	            <SelectItem value="all">All</SelectItem>
408	            <SelectItem value="draft">Draft</SelectItem>
409	            <SelectItem value="sent">Sent</SelectItem>
410	            <SelectItem value="signed">Signed</SelectItem>
411	            <SelectItem value="active">Active</SelectItem>
412	            <SelectItem value="completed">Completed</SelectItem>
413	          </SelectContent>
414	        </Select>
415	        <Select value={sortBy} onValueChange={(v) => setSortBy(v as any)}>
416	          <SelectTrigger className="w-full sm:w-[130px] h-10 rounded-xl bg-muted/50 border-0">
417	            <ArrowUpDown className="h-3.5 w-3.5 mr-1.5 text-muted-foreground" />
418	            <SelectValue />
419	          </SelectTrigger>
420	          <SelectContent>
421	            <SelectItem value="newest">Newest</SelectItem>
422	            <SelectItem value="oldest">Oldest</SelectItem>
423	            <SelectItem value="value">Highest Value</SelectItem>
424	          </SelectContent>
425	        </Select>
426	      </motion.div>
427	
428	      {/* Contracts List */}
429	      <AnimatePresence mode="wait">
430	        {filteredContracts.length === 0 ? (
431	          <motion.div
432	            key="empty"
433	            initial={{ opacity: 0, scale: 0.96 }}
434	            animate={{ opacity: 1, scale: 1 }}
435	            exit={{ opacity: 0 }}
436	          >
437	            <Card className="p-12 md:p-20 text-center border border-dashed border-border/60 bg-muted/20 rounded-3xl">
438	              <div className="w-20 h-20 rounded-3xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center mx-auto mb-6">
439	                <FileSignature className="h-9 w-9 text-primary" />
440	              </div>
441	              <h3 className="font-vollkorn text-2xl font-bold text-foreground mb-2">
442	                {searchQuery || statusFilter !== "all" ? "No contracts found" : "Create your first contract"}
443	              </h3>
444	              <p className="text-muted-foreground mb-8 max-w-md mx-auto text-sm leading-relaxed">
445	                {searchQuery || statusFilter !== "all" 
446	                  ? "Try adjusting your search or filters" 
447	                  : "Build professional contracts with templates, e-signatures, and document management — all in one place."}
448	              </p>
449	              {!searchQuery && statusFilter === "all" && (
450	                <div className="flex flex-col sm:flex-row gap-3 justify-center">
451	                  <Button
452	                    // onClick={() => setCreateDialogOpen(true)}
453	                    onClick={async () => {
454	                      if (isFree) {
455	                         const { count } = await supabase
456	                            .from("contracts")
457	                            .select("*", { count: "exact", head: true });
458	                         if ((count || 0) >= limits.contractsPerMonth) {
459	                           toast.error("You've reached your free plan limit of 5 contracts. Upgrade to Pro for unlimited contracts.");
460	                           return;
461	                         }
462	                       }
463	                   setCreateDialogOpen(true);
464	                  }}
465	                 className="gap-2 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 h-11"
466	                    // className="gap-2 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 h-11"
467	                  >
468	                    <Sparkles className="h-4 w-4" />
469	                    Create from Template
470	                  </Button>
471	                  <Button
472	                    variant="outline"
473	                    onClick={() => setUploadDialogOpen(true)}
474	                    className="gap-2 rounded-xl h-11 border-dashed"
475	                  >
476	                    <Upload className="h-4 w-4" />
477	                    Upload Document
478	                  </Button>
479	                </div>
480	              )}
481	            </Card>
482	          </motion.div>
483	        ) : (
484	          <motion.div key="list" className="space-y-2">
485	            {filteredContracts.map((contract, index) => {
486	              const typeInfo = contractTypeConfig[contract.contract_type] || contractTypeConfig.custom;
487	              const status = statusConfig[contract.status] || statusConfig.draft;
488	              const hasSignatures = contract.creator_signature || contract.client_signature;
489	              const bothSigned = contract.creator_signature && contract.client_signature;
490	              
491	              return (
492	                <motion.div
493	                  key={contract.id}
494	                  initial={{ opacity: 0, y: 8 }}
495	                  animate={{ opacity: 1, y: 0 }}
496	                  transition={{ delay: index * 0.03 }}
497	                >
498	                  <div
499	                    className="group relative flex flex-col gap-4 rounded-2xl border border-border/50 bg-card p-4 transition-all duration-300 hover:border-primary/20 hover:shadow-md hover:shadow-primary/5 cursor-pointer xl:flex-row xl:items-center"
500	                    onClick={() => setPreviewContract(contract)}
501	                  >
502	                    {/* Type Icon */}
503	                    <div className={`hidden sm:flex w-12 h-12 rounded-2xl bg-gradient-to-br ${typeInfo.gradient} items-center justify-center text-lg flex-shrink-0 transition-transform group-hover:scale-105`}>
504	                      {typeInfo.icon}
505	                    </div>
506	
507	                    {/* Content */}
508	                    <div className="flex-1 min-w-0">
509	                      <div className="mb-0.5 flex flex-wrap items-start gap-2">
510	                        <h4 className="min-w-0 break-words font-semibold text-foreground text-sm">
511	                          {contract.title}
512	                        </h4>
513	                        <span className={`inline-flex shrink-0 items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-medium ${status.bg} ${status.color}`}>
514	                          {status.icon}
515	                          {status.label}
516	                        </span>
517	                        {bothSigned && (
518	                          <span className="hidden sm:inline-flex items-center gap-1 px-1.5 py-0.5 rounded-full text-[10px] font-medium bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
519	                            <CheckCircle2 className="h-2.5 w-2.5" />
520	                            Signed
521	                          </span>
522	                        )}
523	                      </div>
524	                      <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted-foreground">
525	                        <span className="flex items-center gap-1">
526	                          <Users className="h-3 w-3" />
527	                          {contract.client_name}
528	                        </span>
529	                        <span className="hidden sm:inline">•</span>
530	                        <span className="hidden sm:flex items-center gap-1">
531	                          {typeInfo.label}
532	                        </span>
533	                        {contract.start_date && (
534	                          <>
535	                            <span className="hidden md:inline">•</span>
536	                            <span className="hidden md:flex items-center gap-1">
537	                              <CalendarDays className="h-3 w-3" />
538	                              {format(new Date(contract.start_date), "MMM d, yyyy")}
539	                            </span>
540	                          </>
541	                        )}
542	                      </div>
543	                    </div>
544	
545	                    {/* Value & Actions */}
546	                    <div className="flex w-full items-center justify-between gap-3 xl:w-auto xl:justify-end" onClick={(e) => e.stopPropagation()}>
547	                      {contract.value && (
548	                        <div className="hidden min-w-[8rem] text-left sm:block xl:text-right">
549	                          <p className="text-sm font-bold text-foreground tabular-nums">
550	                            {formatCurrency(Number(contract.value), contract.currency)}
551	                          </p>
552	                        </div>
553	                      )}
554	                      <DropdownMenu>
555	                        <DropdownMenuTrigger asChild>
556	                          <Button variant="ghost" size="icon" className="h-8 w-8 rounded-xl opacity-100 transition-all xl:opacity-0 xl:group-hover:opacity-100">
557	                            <MoreHorizontal className="h-4 w-4" />
558	                          </Button>
559	                        </DropdownMenuTrigger>
560	                        <DropdownMenuContent align="end" className="w-44 rounded-xl">
561	                          <DropdownMenuItem onClick={() => setPreviewContract(contract)} className="rounded-lg">
562	                            <Eye className="h-4 w-4 mr-2" />
563	                            View & Sign
564	                          </DropdownMenuItem>
565	                          <DropdownMenuItem onClick={() => setEditingContract(contract)} className="rounded-lg">
566	                            <Edit className="h-4 w-4 mr-2" />
567	                            Edit
568	                          </DropdownMenuItem>
569	                          <DropdownMenuItem onClick={() => handleDuplicate(contract)} className="rounded-lg">
570	                            <Copy className="h-4 w-4 mr-2" />
571	                            Duplicate
572	                          </DropdownMenuItem>
573	                          <DropdownMenuSeparator />
574	                          {contract.status === "draft" && (
575	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "sent")} className="rounded-lg">
576	                              <Send className="h-4 w-4 mr-2" />
577	                              Mark as Sent
578	                            </DropdownMenuItem>
579	                          )}
580	                          {contract.status === "sent" && (
581	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "signed")} className="rounded-lg">
582	                              <FileSignature className="h-4 w-4 mr-2" />
583	                              Mark as Signed
584	                            </DropdownMenuItem>
585	                          )}
586	                          {contract.status === "signed" && (
587	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "active")} className="rounded-lg">
588	                              <CheckCircle2 className="h-4 w-4 mr-2" />
589	                              Mark Active
590	                            </DropdownMenuItem>
591	                          )}
592	                          {contract.status === "active" && (
593	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "completed")} className="rounded-lg">
594	                              <CheckCircle2 className="h-4 w-4 mr-2" />
595	                              Complete
596	                            </DropdownMenuItem>
597	                          )}
598	                          <DropdownMenuSeparator />
599	                          <DropdownMenuItem
600	                            className="text-destructive focus:text-destructive rounded-lg"
601	                            onClick={() => handleDelete(contract.id)}
602	                          >
603	                            <Trash2 className="h-4 w-4 mr-2" />
604	                            Delete
605	                          </DropdownMenuItem>
606	                        </DropdownMenuContent>
607	                      </DropdownMenu>
608	                    </div>
609	                  </div>
610	                </motion.div>
611	              );
612	            })}
613	          </motion.div>
614	        )}
615	      </AnimatePresence>
616	
617	      <CreateContractDialog
618	        open={createDialogOpen || !!editingContract}
619	        onOpenChange={(open) => {
620	          setCreateDialogOpen(open);
621	          if (!open) setEditingContract(null);
622	        }}
623	        editingContract={editingContract}
624	        onSuccess={fetchContracts}
625	      />
626	
627	      <UploadContractDialog
628	        open={uploadDialogOpen}
629	        onOpenChange={setUploadDialogOpen}
630	        onUpload={handleFileUpload}
631	      />
632	
633	      <ContractPreviewDialog
634	        open={!!previewContract}
635	        onOpenChange={(open) => !open && setPreviewContract(null)}
636	        contract={previewContract}
637	        onContractUpdate={fetchContracts}
638	      />
639	    </div>
640	  );
641	};
