452	              <div className="w-20 h-20 rounded-3xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center mx-auto mb-6">
453	                <FileSignature className="h-9 w-9 text-primary" />
454	              </div>
455	              <h3 className="font-vollkorn text-2xl font-bold text-foreground mb-2">
456	                {searchQuery || statusFilter !== "all" ? "No contracts found" : "Create your first contract"}
457	              </h3>
458	              <p className="text-muted-foreground mb-8 max-w-md mx-auto text-sm leading-relaxed">
459	                {searchQuery || statusFilter !== "all" 
460	                  ? "Try adjusting your search or filters" 
461	                  : "Build professional contracts with templates, e-signatures, and document management — all in one place."}
462	              </p>
463	              {!searchQuery && statusFilter === "all" && (
464	                <div className="flex flex-col sm:flex-row gap-3 justify-center">
465	                  <Button
466	                    // onClick={() => setCreateDialogOpen(true)}
467	                    onClick={async () => {
468	                      if (isFree) {
469	                         const { count } = await supabase
470	                            .from("contracts")
471	                            .select("*", { count: "exact", head: true });
472	                         if ((count || 0) >= limits.contractsPerMonth) {
473	                           toast.error("You've reached your free plan limit of 5 contracts. Upgrade to Pro for unlimited contracts.");
474	                           return;
475	                         }
476	                       }
477	                   setCreateDialogOpen(true);
478	                  }}
479	                 className="gap-2 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 h-11"
480	                    // className="gap-2 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 h-11"
481	                  >
482	                    <Sparkles className="h-4 w-4" />
483	                    Create from Template
484	                  </Button>
485	                  <Button
486	                    variant="outline"
487	                    onClick={() => setUploadDialogOpen(true)}
488	                    className="gap-2 rounded-xl h-11 border-dashed"
489	                  >
490	                    <Upload className="h-4 w-4" />
491	                    Upload Document
492	                  </Button>
493	                </div>
494	              )}
495	            </Card>
496	          </motion.div>
497	        ) : (
498	          <motion.div key="list" className="space-y-2">
499	            {filteredContracts.map((contract, index) => {
500	              const typeInfo = contractTypeConfig[contract.contract_type] || contractTypeConfig.custom;
501	              const status = statusConfig[contract.status] || statusConfig.draft;
502	              const hasSignatures = contract.creator_signature || contract.client_signature;
503	              const bothSigned = contract.creator_signature && contract.client_signature;
504	              
505	              return (
506	                <motion.div
507	                  key={contract.id}
508	                  initial={{ opacity: 0, y: 8 }}
509	                  animate={{ opacity: 1, y: 0 }}
510	                  transition={{ delay: index * 0.03 }}
511	                >
512	                  <div
513	                    className="group relative flex flex-col gap-4 rounded-2xl border border-border/50 bg-card p-4 transition-all duration-300 hover:border-primary/20 hover:shadow-md hover:shadow-primary/5 cursor-pointer xl:flex-row xl:items-center"
514	                    onClick={() => setPreviewContract(contract)}
515	                  >
516	                    {/* Type Icon */}
517	                    <div className={`hidden sm:flex w-12 h-12 rounded-2xl bg-gradient-to-br ${typeInfo.gradient} items-center justify-center text-lg flex-shrink-0 transition-transform group-hover:scale-105`}>
518	                      {typeInfo.icon}
519	                    </div>
520	
521	                    {/* Content */}
522	                    <div className="flex-1 min-w-0">
523	                      <div className="mb-0.5 flex flex-wrap items-start gap-2">
524	                        {renamingId === contract.id ? (
525	                          <form
526	                            onSubmit={e => { e.preventDefault(); handleRename(contract.id); }}
527	                            className="flex items-center gap-1.5 min-w-0"
528	                            onClick={e => e.stopPropagation()}
529	                          >
530	                            <input
531	                              autoFocus
532	                              value={renameValue}
533	                              onChange={e => setRenameValue(e.target.value)}
534	                              onKeyDown={e => e.key === "Escape" && setRenamingId(null)}
535	                              className="h-7 text-sm rounded-lg border border-primary/40 bg-background px-2 focus:outline-none focus:ring-1 focus:ring-primary/40 min-w-0 w-40 sm:w-52"
536	                            />
537	                            <button type="submit" className="h-7 px-2.5 text-xs rounded-lg bg-primary text-white hover:bg-primary/90 font-medium flex-shrink-0">
538	                              Save
539	                            </button>
540	                            <button type="button" onClick={() => setRenamingId(null)} className="h-7 w-7 flex items-center justify-center rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted flex-shrink-0">
541	                              <X className="h-3.5 w-3.5" />
542	                            </button>
543	                          </form>
544	                        ) : (
545	                          <h4 className="min-w-0 break-words font-semibold text-foreground text-sm">
546	                            {contract.title}
547	                          </h4>
548	                        )}
549	                        <span className={`inline-flex shrink-0 items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-medium ${status.bg} ${status.color}`}>
550	                          {status.icon}
551	                          {status.label}
552	                        </span>
553	                        {bothSigned && (
554	                          <span className="hidden sm:inline-flex items-center gap-1 px-1.5 py-0.5 rounded-full text-[10px] font-medium bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
555	                            <CheckCircle2 className="h-2.5 w-2.5" />
556	                            Signed
557	                          </span>
558	                        )}
559	                      </div>
560	                      <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted-foreground">
561	                        <span className="flex items-center gap-1">
562	                          <Users className="h-3 w-3" />
563	                          {contract.client_name}
564	                        </span>
565	                        <span className="hidden sm:inline">•</span>
566	                        <span className="hidden sm:flex items-center gap-1">
567	                          {typeInfo.label}
568	                        </span>
569	                        {contract.start_date && (
570	                          <>
571	                            <span className="hidden md:inline">•</span>
572	                            <span className="hidden md:flex items-center gap-1">
573	                              <CalendarDays className="h-3 w-3" />
574	                              {format(new Date(contract.start_date), "MMM d, yyyy")}
575	                            </span>
576	                          </>
577	                        )}
578	                      </div>
579	                    </div>
580	
581	                    {/* Value & Actions */}
582	                    <div className="flex w-full items-center justify-between gap-3 xl:w-auto xl:justify-end" onClick={(e) => e.stopPropagation()}>
583	                      {contract.value && (
584	                        <div className="hidden min-w-[8rem] text-left sm:block xl:text-right">
585	                          <p className="text-sm font-bold text-foreground tabular-nums">
586	                            {formatCurrency(Number(contract.value), contract.currency)}
587	                          </p>
588	                        </div>
589	                      )}
590	                      <DropdownMenu>
591	                        <DropdownMenuTrigger asChild>
592	                          <Button variant="ghost" size="icon" className="h-8 w-8 rounded-xl opacity-100 transition-all xl:opacity-0 xl:group-hover:opacity-100">
593	                            <MoreHorizontal className="h-4 w-4" />
594	                          </Button>
595	                        </DropdownMenuTrigger>
596	                        <DropdownMenuContent align="end" className="w-44 rounded-xl">
597	                          <DropdownMenuItem onClick={() => setPreviewContract(contract)} className="rounded-lg">
598	                            <Eye className="h-4 w-4 mr-2" />
599	                            View & Sign
600	                          </DropdownMenuItem>
601	                          <DropdownMenuItem onClick={() => setEditingContract(contract)} className="rounded-lg">
602	                            <Edit className="h-4 w-4 mr-2" />
603	                            Edit
604	                          </DropdownMenuItem>
605	                          <DropdownMenuItem onClick={() => handleDuplicate(contract)} className="rounded-lg">
606	                            <Copy className="h-4 w-4 mr-2" />
607	                            Duplicate
608	                          </DropdownMenuItem>
609	                          <DropdownMenuSeparator />
610	                          {contract.status === "draft" && (
611	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "sent")} className="rounded-lg">
612	                              <Send className="h-4 w-4 mr-2" />
613	                              Mark as Sent
614	                            </DropdownMenuItem>
615	                          )}
616	                          {contract.status === "sent" && (
617	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "signed")} className="rounded-lg">
618	                              <FileSignature className="h-4 w-4 mr-2" />
619	                              Mark as Signed
620	                            </DropdownMenuItem>
621	                          )}
622	                          {contract.status === "signed" && (
623	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "active")} className="rounded-lg">
624	                              <CheckCircle2 className="h-4 w-4 mr-2" />
625	                              Mark Active
626	                            </DropdownMenuItem>
627	                          )}
628	                          {contract.status === "active" && (
629	                            <DropdownMenuItem onClick={() => handleStatusChange(contract.id, "completed")} className="rounded-lg">
630	                              <CheckCircle2 className="h-4 w-4 mr-2" />
631	                              Complete
632	                            </DropdownMenuItem>
633	                          )}
634	                          <DropdownMenuSeparator />
635	                          <DropdownMenuItem
636	                            className="text-destructive focus:text-destructive rounded-lg"
637	                            onClick={() => handleDelete(contract.id)}
638	                          >
639	                            <Trash2 className="h-4 w-4 mr-2" />
640	                            Delete
641	                          </DropdownMenuItem>
642	                        </DropdownMenuContent>
643	                      </DropdownMenu>
644	                    </div>
645	                  </div>
646	                </motion.div>
647	              );
648	            })}
649	          </motion.div>
650	        )}
651	      </AnimatePresence>
652	
653	      <CreateContractDialog
654	        open={createDialogOpen || !!editingContract}
655	        onOpenChange={(open) => {
656	          setCreateDialogOpen(open);
657	          if (!open) setEditingContract(null);
658	        }}
659	        editingContract={editingContract}
660	        onSuccess={fetchContracts}
661	      />
662	
663	      <UploadContractDialog
664	        open={uploadDialogOpen}
665	        onOpenChange={setUploadDialogOpen}
666	        onUpload={handleFileUpload}
667	      />
668	
669	      <ContractPreviewDialog
670	        open={!!previewContract}
671	        onOpenChange={(open) => !open && setPreviewContract(null)}
672	        contract={previewContract}
673	        onContractUpdate={fetchContracts}
674	      />
675	    </div>
676	  );
677	};
678	
679	export default ContractsTab;
