1	import { useState, useEffect, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import {
5	  Dialog,
6	  DialogContent,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Textarea } from "@/components/ui/textarea";
10	import {
11	  Printer, CheckCircle2, PenTool,
12	  Edit3, Save, X, Maximize2, Minimize2, Download,
13	} from "lucide-react";
14	import { format } from "date-fns";
15	import { toast } from "sonner";
16	import { cn } from "@/lib/utils";
17	import ESignatureDialog from "./ESignatureDialog";
18	import { useDownloadPDF } from "@/hooks/use-download-pdf";
19	
20	// ─── Types ────────────────────────────────────────────────────────────────────
21	
22	interface SigPos { x: number; y: number; w: number; h: number }
23	
24	const MIN_W   = 80;
25	const MIN_H   = 40;
26	const INIT_W  = 220;
27	const INIT_H  = 88;
28	
29	// ─── Draggable + resizable widget ─────────────────────────────────────────────
30	// Must live outside ContractPreviewDialog so React never unmounts it on parent
31	// re-renders during an active drag.
32	
33	interface DraggableSigProps {
34	  pos:       SigPos;
35	  signature: string;
36	  onChange:  (p: SigPos) => void;
37	}
38	
39	const DraggableSig = ({ pos, signature, onChange }: DraggableSigProps) => {
40	  const dragRef   = useRef<{ sx: number; sy: number; ox: number; oy: number } | null>(null);
41	  const resizeRef = useRef<{ corner: string; sx: number; sy: number; orig: SigPos } | null>(null);
42	
43	  // drag body
44	  const onBodyDown = (e: React.PointerEvent<HTMLDivElement>) => {
45	    e.preventDefault();
46	    e.stopPropagation();
47	    e.currentTarget.setPointerCapture(e.pointerId);
48	    dragRef.current = { sx: e.clientX, sy: e.clientY, ox: pos.x, oy: pos.y };
49	  };
50	  const onBodyMove = (e: React.PointerEvent<HTMLDivElement>) => {
51	    if (!dragRef.current) return;
52	    onChange({ ...pos, x: dragRef.current.ox + (e.clientX - dragRef.current.sx), y: dragRef.current.oy + (e.clientY - dragRef.current.sy) });
53	  };
54	  const onBodyUp = () => { dragRef.current = null; };
55	
56	  // resize corners
57	  const ch = (corner: string) => ({
58	    onPointerDown: (e: React.PointerEvent<HTMLDivElement>) => {
59	      e.preventDefault();
60	      e.stopPropagation();
61	      e.currentTarget.setPointerCapture(e.pointerId);
62	      resizeRef.current = { corner, sx: e.clientX, sy: e.clientY, orig: { ...pos } };
63	    },
64	    onPointerMove: (e: React.PointerEvent<HTMLDivElement>) => {
65	      if (!resizeRef.current || resizeRef.current.corner !== corner) return;
66	      const dx = e.clientX - resizeRef.current.sx;
67	      const dy = e.clientY - resizeRef.current.sy;
68	      const o  = resizeRef.current.orig;
69	      let { x, y, w, h } = o;
70	      if (corner === "se") { w = Math.max(MIN_W, o.w + dx);                                 h = Math.max(MIN_H, o.h + dy); }
71	      if (corner === "sw") { x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx); h = Math.max(MIN_H, o.h + dy); }
72	      if (corner === "ne") { w = Math.max(MIN_W, o.w + dx); y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy); }
73	      if (corner === "nw") {
74	        x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx);
75	        y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy);
76	      }
77	      onChange({ x, y, w, h });
78	    },
79	    onPointerUp: () => { resizeRef.current = null; },
80	  });
81	
82	  const corners = [
83	    { id: "nw", cls: "-top-2 -left-2 cursor-nw-resize" },
84	    { id: "ne", cls: "-top-2 -right-2 cursor-ne-resize" },
85	    { id: "sw", cls: "-bottom-2 -left-2 cursor-sw-resize" },
86	    { id: "se", cls: "-bottom-2 -right-2 cursor-se-resize" },
87	  ];
88	
89	  const fs = Math.max(14, Math.min(pos.h * 0.40, 48));
90	
91	  return (
92	    <div
93	      className="absolute touch-none select-none"
94	      style={{ left: pos.x, top: pos.y, width: pos.w, height: pos.h, zIndex: 60 }}
95	      onClick={e => e.stopPropagation()}
96	    >
97	      {/* body */}
98	      <div
99	        className="w-full h-full rounded-lg border-2 border-primary/80 bg-white/96 dark:bg-zinc-900/96 shadow-[0_8px_32px_rgba(0,0,0,0.22)] flex items-center justify-center overflow-hidden cursor-move"
100	        onPointerDown={onBodyDown}
101	        onPointerMove={onBodyMove}
102	        onPointerUp={onBodyUp}
103	      >
104	        {signature.startsWith("data:image") ? (
105	          <img src={signature} alt="sig" className="max-w-full max-h-full object-contain p-1" draggable={false} />
106	        ) : (
107	          <span className="font-vollkorn italic text-foreground/85 truncate px-2 pointer-events-none" style={{ fontSize: fs }}>
108	            {signature}
109	          </span>
110	        )}
111	      </div>
112	
113	      {/* corner resize handles */}
114	      {corners.map(({ id, cls }) => (
115	        <div
116	          key={id}
117	          className={cn("absolute w-4 h-4 bg-white border-2 border-primary rounded-sm shadow-md touch-none z-10", cls)}
118	          {...ch(id)}
119	        />
120	      ))}
121	    </div>
122	  );
123	};
124	
125	// ─── Main Dialog ──────────────────────────────────────────────────────────────
126	
127	interface ContractPreviewDialogProps {
128	  open: boolean;
129	  onOpenChange: (open: boolean) => void;
130	  contract: any;
131	  onContractUpdate?: () => void;
132	}
133	
134	const ContractPreviewDialog = ({
135	  open,
136	  onOpenChange,
137	  contract,
138	  onContractUpdate,
139	}: ContractPreviewDialogProps) => {
140	  const [profile, setProfile]                           = useState<any>(null);
141	  const [showSignatureDialog, setShowSignatureDialog]   = useState(false);
142	  const [placementMode, setPlacementMode]               = useState<{
143	    signature: string;
144	    signedAt:  string;
145	    pos:       SigPos | null;
146	  } | null>(null);
147	  const [savingSignature, setSavingSignature]           = useState(false);
148	  const [localContract, setLocalContract]               = useState(contract);
149	  const [isEditingDetails, setIsEditingDetails]         = useState(false);
150	  const [editableContent, setEditableContent]           = useState("");
151	  const [savingDetails, setSavingDetails]               = useState(false);
152	  const [isFullscreen, setIsFullscreen]                 = useState(false);
153	
154	  // ref on the INNER content padding div — DraggableSig lives inside here
155	  // so the signature is literally embedded in the document body
156	  const contentAreaRef = useRef<HTMLDivElement>(null);
157	
158	  const { ref: docRef, download, downloading } = useDownloadPDF(
159	    contract ? `Contract-${contract.title?.replace(/\s+/g, "-")}` : "Contract"
160	  );
161	
162	  useEffect(() => {
163	    if (contract) {
164	      fetchProfile();
165	      setLocalContract(contract);
166	      setEditableContent(contract.content || "");
167	      setIsEditingDetails(false);
168	      setPlacementMode(null);
169	    }
170	  }, [contract]);
171	
172	  const fetchProfile = async () => {
173	    const { data: { session } } = await supabase.auth.getSession();
174	    if (session) {
175	      const { data } = await supabase.from("profiles").select("*").eq("id", session.user.id).single();
176	      setProfile(data);
177	    }
178	  };
179	
180	  // ESignatureDialog finished → enter placement mode, switch to view
181	  const handleSignReady = (signature: string, signedAt: string) => {
182	    setShowSignatureDialog(false);
183	    setIsEditingDetails(false);
184	    setPlacementMode({ signature, signedAt, pos: null });
185	  };
186	
187	  // First tap on the document content area → drop the widget at that exact point
188	  const handleContentTap = (e: React.MouseEvent<HTMLDivElement>) => {
189	    if (!placementMode || placementMode.pos || !contentAreaRef.current) return;
190	    e.stopPropagation();
191	    const rect = contentAreaRef.current.getBoundingClientRect();
192	    const x    = e.clientX - rect.left - INIT_W / 2;
193	    const y    = e.clientY - rect.top  - INIT_H / 2;
194	    setPlacementMode(prev =>
195	      prev ? { ...prev, pos: { x: Math.max(0, x), y: Math.max(0, y), w: INIT_W, h: INIT_H } } : prev
196	    );
197	  };
198	
199	  // Confirm → save to DB
200	  const handleConfirm = async () => {
201	    if (!placementMode?.pos || !localContract) return;
202	    setSavingSignature(true);
203	    const { signature, signedAt, pos } = placementMode;
204	    const { error } = await supabase
205	      .from("contracts")
206	      .update({
207	        creator_signature:  signature,
208	        creator_signed_at:  signedAt,
209	        signature_position: pos as any,
210	        status:             "signed",
211	      })
212	      .eq("id", localContract.id);
213	    setSavingSignature(false);
214	    if (error) { toast.error("Failed to save signature"); return; }
215	    setLocalContract({ ...localContract, creator_signature: signature, creator_signed_at: signedAt, signature_position: pos, status: "signed" });
216	    setPlacementMode(null);
217	    toast.success("Signature placed and saved!");
218	    onContractUpdate?.();
219	  };
220	
221	  const handleSaveDetails = async () => {
222	    if (!localContract) return;
223	    setSavingDetails(true);
224	    const { error } = await supabase.from("contracts").update({ content: editableContent || null }).eq("id", localContract.id);
225	    setSavingDetails(false);
226	    if (error) { toast.error("Failed to save changes"); return; }
227	    setLocalContract({ ...localContract, content: editableContent || null });
228	    setIsEditingDetails(false);
229	    toast.success("Contract updated");
230	    onContractUpdate?.();
231	  };
232	
233	  if (!contract || !localContract) return null;
234	
235	  const statusConfig: Record<string, { label: string; color: string; bg: string }> = {
236	    draft:     { label: "Draft",     color: "text-muted-foreground", bg: "bg-muted" },
237	    sent:      { label: "Sent",      color: "text-blue-600",         bg: "bg-blue-500/10" },
238	    signed:    { label: "Signed",    color: "text-emerald-600",      bg: "bg-emerald-500/10" },
239	    active:    { label: "Active",    color: "text-green-600",        bg: "bg-green-500/10" },
240	    completed: { label: "Completed", color: "text-purple-600",       bg: "bg-purple-500/10" },
241	    cancelled: { label: "Cancelled", color: "text-destructive",      bg: "bg-destructive/10" },
242	  };
243	
244	  const status   = statusConfig[localContract.status] || statusConfig.draft;
245	  const savedPos = localContract.signature_position as SigPos | null;
246	
247	  return (
248	    <Dialog open={open} onOpenChange={v => { if (!v) { setIsFullscreen(false); setPlacementMode(null); } onOpenChange(v); }}>
249	      <DialogContent className={cn(
250	        "overflow-hidden flex flex-col p-0 gap-0 transition-all duration-300",
251	        isFullscreen ? "max-w-[100vw] w-screen h-screen max-h-screen rounded-none" : "max-w-4xl max-h-[92vh] rounded-2xl"
252	      )}>
253	
254	        {/* Print stylesheet — shows only the contract text content */}
255	        <style>{`
256	          @media print {
257	            body, body * { visibility: hidden; }
258	            .crevia-print-area, .crevia-print-area * { visibility: visible; }
259	            .crevia-print-area {
260	              position: fixed;
261	              top: 0; left: 0;
262	              width: 100%;
263	              padding: 40px;
264	              background: white;
265	              font-family: ui-monospace, monospace;
266	            }
267	          }
268	        `}</style>
269	
270	        {/* ── Top Bar ── */}
271	        <div className="print:hidden sticky top-0 z-10 bg-background border-b border-border/50 px-4 py-2.5 flex items-center justify-between gap-2">
272	          <div className="flex items-center gap-2 min-w-0">
273	            <DialogTitle className="font-vollkorn text-sm sm:text-base truncate">{localContract.title}</DialogTitle>
274	            <span className={cn("inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] font-medium flex-shrink-0", status.bg, status.color)}>
275	              {status.label}
276	            </span>
277	          </div>
278	          <div className="flex items-center gap-1 flex-shrink-0">
279	            {!isEditingDetails && !placementMode && (
280	              <Button variant="ghost" size="sm"
281	                onClick={() => { setIsEditingDetails(true); setEditableContent(localContract.content || ""); }}
282	                className="gap-1 h-8 w-8 sm:w-auto sm:px-2.5 rounded-lg"
283	              >
284	                <Edit3 className="h-3.5 w-3.5" />
285	                <span className="hidden sm:inline text-xs">Edit</span>
286	              </Button>
287	            )}
288	            {/* Sign button — only when unsigned and not in placement/edit mode */}
289	            {!isEditingDetails && !placementMode && !localContract.creator_signature && (
290	              <Button variant="ghost" size="sm"
291	                onClick={() => setShowSignatureDialog(true)}
292	                className="gap-1 h-8 w-8 sm:w-auto sm:px-2.5 rounded-lg text-primary hover:bg-primary/10"
293	              >
294	                <PenTool className="h-3.5 w-3.5" />
295	                <span className="hidden sm:inline text-xs">Sign</span>
296	              </Button>
297	            )}
298	            {!placementMode && (
299	              <>
300	                <Button variant="ghost" size="sm" onClick={download} disabled={downloading} className="gap-1 h-8 w-8 sm:w-auto sm:px-2.5 rounded-lg">
301	                  <Download className="h-3.5 w-3.5" />
302	                  <span className="hidden sm:inline text-xs">{downloading ? "Saving…" : "Download"}</span>
303	                </Button>
